        //selector
        [SerializeField] private SelectorDecoder selectorDecoder;

        //thumbnail
        [SerializeField] private ThumbnailDecoder thumbnailDecoder;

        //------------------private--------------
        private LoadingManegerCallBack _callBack;

        //------------------Selector--------------
        public bool TrySelectorDecodeStart(LoadingManegerCallBack loadingManegerCallBack)
        {
            if (selectorDecoder.IsBusy)
            {
                return false;
            }
            _callBack = loadingManegerCallBack;
            selectorDecoder.GetSelectorInfo(selectorTextUrl, this, nameof(OnSelectorDecodeEnd));
            return true;
        }

        public void OnSelectorDecodeEnd()
        {
            _callBack.OnSelectorDecodeEnd(selectorDecoder.Result, selectorDecoder.Si, selectorDecoder.EventBunners, selectorDecoder.ErrorKind, selectorDecoder.ErrorMessage);
        }

        //------------------Thumbnail--------------
        public bool TryGetThumbnailStart(int urlIndex, int innerIndex, LoadingManegerCallBack loadingManegerCallBack)
        {
            if (thumbnailDecoder.IsBusy)
            {
                return false;
            }
            _callBack = loadingManegerCallBack;
            var url = thumbnailTextUrls[urlIndex];
            thumbnailDecoder.GetThumbnail(urlIndex, innerIndex, url, this, nameof(OnThumbnailDecodeEnd));
            return true;
        }

        public void OnThumbnailDecodeEnd()
        {
            _callBack.OnThumbnaiDecodeEnd(thumbnailDecoder.Result, thumbnailDecoder.Thumbnail, thumbnailDecoder.ErrorKind, thumbnailDecoder.ErrorMessage);
        }

        //----------------Check----------------------

        //Decoder is using.
        [HideInInspector]
        public bool IsBusy
        {
            get { return selectorDecoder.IsBusy || thumbnailDecoder.IsBusy; }
        }
    }
